  1→#!/usr/bin/env node
  2→/**
  3→ * P1 — 智能切分
  4→ *
  5→ * 读取 script.json，按 shot 为一级单元，在 shot 内按句子做二级切分。
  6→ * 输出 chunks.json，保留 text（原文，用于字幕）和 text_normalized（TTS 输入）。
  7→ *
  8→ * Usage:
  9→ *   node scripts/p1-chunk.js --script <script.json> --outdir <dir>
 10→ */
 11→
 12→const fs = require("fs");
 13→const path = require("path");
 14→
 15→// --- 配置 ---
 16→const MAX_CHARS_PER_CHUNK = 200;
 17→const MAX_SENTENCES_PER_CHUNK = 5;
 18→const MIN_SENTENCES_PER_CHUNK = 2;
 19→
 20→// --- 参数解析 ---
 21→const args = process.argv.slice(2);
 22→let scriptPath = "";
 23→let outdir = "";
 24→
 25→for (let i = 0; i < args.length; i++) {
 26→  if (args[i] === "--script" && args[i + 1]) scriptPath = args[++i];
 27→  else if (args[i] === "--outdir" && args[i + 1]) outdir = args[++i];
 28→}
 29→
 30→if (!scriptPath || !outdir) {
 31→  console.error(
 32→    "Usage: node p1-chunk.js --script <script.json> --outdir <dir>"
 33→  );
 34→  process.exit(1);
 35→}
 36→
 37→// =============================================================
 38→// 文本规范化（TTS 预处理）
 39→// =============================================================
 40→
 41→function normalize(text) {
 42→  let t = text;
 43→
 44→  // 删除导演标注 [...] 和停顿标记
 45→  t = t.replace(/\[.*?\]/g, "");
 46→  t = t.replace(/（停顿.*?）/g, "");
 47→  t = t.replace(/\(停顿.*?\)/g, "");
 48→
 49→  // 特殊符号替换
 50→  t = t.replace(/(\d+)\s*-\s*(\d+)/g, "$1到$2"); // 28-35 → 28到35
 51→  t = t.replace(/(\d+)%/g, "百分之$1"); // 53% → 百分之53
 52→
 53→  // 英文品牌名后加句号隔断（中英交界）
 54→  t = t.replace(/([a-zA-Z]{2,})([\u4e00-\u9fff])/g, "$1. $2");
 55→
 56→  return t.replace(/\s+/g, " ").trim();
 57→}
 58→
 59→// =============================================================
 60→// 句子切分
 61→// =============================================================
 62→
 63→/**
 64→ * 按中文句号、问号、感叹号、分号切分，保留分隔符
 65→ */
 66→function splitSentences(text) {
 67→  const parts = text.split(/(?<=[。？！；\n])/);
 68→  return parts.map((s) => s.trim()).filter((s) => s.length > 0);
 69→}
 70→
 71→/**
 72→ * 将句子列表按规则打包成 chunks
 73→ */
 74→function packChunks(sentences, shotId) {
 75→  const chunks = [];
 76→  let buffer = [];
 77→  let bufferLen = 0;
 78→
 79→  function flush() {
 80→    if (buffer.length === 0) return;
 81→    const text = buffer.join("");
 82→    chunks.push({
 83→      id: `${shotId}_chunk${String(chunks.length + 1).padStart(2, "0")}`,
 84→      shot_id: shotId,
 85→      text: text,
 86→      text_normalized: normalize(text),
 87→      sentence_count: buffer.length,
 88→      char_count: text.length,
 89→      status: "pending",
 90→    });
 91→    buffer = [];
 92→    bufferLen = 0;
 93→  }
 94→
 95→  for (const sentence of sentences) {
 96→    // 如果加入后超限，且 buffer 已有内容，先 flush
 97→    if (
 98→      buffer.length > 0 &&
 99→      (buffer.length >= MAX_SENTENCES_PER_CHUNK ||
100→        bufferLen + sentence.length > MAX_CHARS_PER_CHUNK)
101→    ) {
102→      flush();
103→    }
104→    buffer.push(sentence);
105→    bufferLen += sentence.length;
106→  }
107→  flush();
108→
109→  // 最小片段保护：如果最后一个 chunk 只有 1 句且前面有 chunk，合并到前一个
110→  if (
111→    chunks.length > 1 &&
112→    chunks[chunks.length - 1].sentence_count < MIN_SENTENCES_PER_CHUNK
113→  ) {
114→    const last = chunks.pop();
115→    const prev = chunks[chunks.length - 1];
116→    const merged = prev.text + last.text;
117→    prev.text = merged;
118→    prev.text_normalized = normalize(merged);
119→    prev.sentence_count += last.sentence_count;
120→    prev.char_count = merged.length;
121→  }
122→
123→  return chunks;
124→}
125→
126→// =============================================================
127→// Main
128→// =============================================================
129→
130→function main() {
131→  const script = JSON.parse(fs.readFileSync(scriptPath, "utf-8"));
132→  const segments = script.segments || script.shots || [];
133→
134→  if (segments.length === 0) {
135→    console.error("No segments found in script");
136→    process.exit(1);
137→  }
138→
139→  fs.mkdirSync(outdir, { recursive: true });
140→
141→  const allChunks = [];
142→
143→  for (const seg of segments) {
144→    const shotId = typeof seg.id === "number"
145→      ? `shot${String(seg.id).padStart(2, "0")}`
146→      : seg.id;
147→    const text = seg.tts_text || seg.text || seg.narration || "";
148→
149→    if (!text) {
150→      console.log(`  [SKIP] ${shotId} — no text`);
151→      continue;
152→    }
153→
154→    const sentences = splitSentences(text);
155→    const chunks = packChunks(sentences, shotId);
156→
157→    console.log(
158→      `  ${shotId}: ${text.length} chars → ${chunks.length} chunk(s) [${chunks.map((c) => c.sentence_count + "句").join(", ")}]`
159→    );
160→
161→    allChunks.push(...chunks);
162→  }
163→
164→  // 写入 chunks.json
165→  const outPath = path.join(outdir, "chunks.json");
166→  fs.writeFileSync(outPath, JSON.stringify(allChunks, null, 2));
167→
168→  console.log(`\n=== Output: ${outPath} ===`);
169→  console.log(`  Total chunks: ${allChunks.length}`);
170→  console.log(
171→    `  Total chars: ${allChunks.reduce((s, c) => s + c.char_count, 0)}`
172→  );
173→
174→  // 可逆性校验
175→  const segTexts = segments
176→    .map((s) => s.tts_text || s.text || s.narration || "")
177→    .filter(Boolean);
178→  const reconstructed = [];
179→  let ci = 0;
180→  for (const seg of segments) {
181→    const shotId = typeof seg.id === "number"
182→      ? `shot${String(seg.id).padStart(2, "0")}`
183→      : seg.id;
184→    const shotChunks = allChunks.filter((c) => c.shot_id === shotId);
185→    reconstructed.push(shotChunks.map((c) => c.text).join(""));
186→  }
187→
188→  const original = segTexts.join("");
189→  const rebuilt = reconstructed.join("");
190→  if (original === rebuilt) {
191→    console.log("  ✓ 可逆性校验通过");
192→  } else {
193→    console.error("  ✗ 可逆性校验失败！切分后无法还原原始文本");
194→    process.exit(1);
195→  }
196→}
197→
198→main();
