  1→#!/usr/bin/env node
  2→/**
  3→ * P2 — 并行 TTS 合成
  4→ *
  5→ * 读取 chunks.json，对每个 pending chunk 调用 Fish TTS，输出独立 WAV。
  6→ * 支持指定单个 chunk 重做（--chunk <id>）。
  7→ *
  8→ * Usage:
  9→ *   node scripts/p2-synth.js --chunks <chunks.json> --outdir <dir>
 10→ *   node scripts/p2-synth.js --chunks <chunks.json> --outdir <dir> --chunk shot02_chunk01
 11→ */
 12→
 13→const fs = require("fs");
 14→const path = require("path");
 15→const { execSync } = require("child_process");
 16→const http = require("http");
 17→const tls = require("tls");
 18→
 19→// --- 配置 ---
 20→const TTS_API_URL = "https://api.fish.audio/v1/tts";
 21→const TTS_API_KEY = process.env.FISH_TTS_KEY;
 22→if (!TTS_API_KEY) {
 23→  console.error("ERROR: FISH_TTS_KEY environment variable is required");
 24→  process.exit(1);
 25→}
 26→const TTS_MODEL = process.env.FISH_TTS_MODEL || "s1";
 27→const TTS_REFERENCE_ID = process.env.FISH_TTS_REFERENCE_ID || "";
 28→const DEFAULT_SPEED = parseFloat(process.env.TTS_SPEED || "1.0");
 29→const CONCURRENCY = 3;
 30→
 31→// --- 参数解析 ---
 32→const args = process.argv.slice(2);
 33→let chunksPath = "";
 34→let outdir = "";
 35→let targetChunk = "";
 36→let speed = DEFAULT_SPEED;
 37→
 38→for (let i = 0; i < args.length; i++) {
 39→  if (args[i] === "--chunks" && args[i + 1]) chunksPath = args[++i];
 40→  else if (args[i] === "--outdir" && args[i + 1]) outdir = args[++i];
 41→  else if (args[i] === "--chunk" && args[i + 1]) targetChunk = args[++i];
 42→  else if (args[i] === "--speed" && args[i + 1]) speed = parseFloat(args[++i]);
 43→}
 44→
 45→if (!chunksPath || !outdir) {
 46→  console.error(
 47→    "Usage: node p2-synth.js --chunks <chunks.json> --outdir <dir> [--chunk <id>] [--speed 1.15]"
 48→  );
 49→  process.exit(1);
 50→}
 51→
 52→// =============================================================
 53→// TTS API (via ClashX HTTPS proxy tunnel)
 54→// =============================================================
 55→
 56→const PROXY_HOST = "127.0.0.1";
 57→const PROXY_PORT = 7890;
 58→
 59→function callTTS(text) {
 60→  return new Promise((resolve, reject) => {
 61→    const targetHost = "api.fish.audio";
 62→    const targetPort = 443;
 63→
 64→    // Step 1: CONNECT to proxy
 65→    const proxyReq = http.request({
 66→      host: PROXY_HOST,
 67→      port: PROXY_PORT,
 68→      method: "CONNECT",
 69→      path: `${targetHost}:${targetPort}`,
 70→    });
 71→
 72→    proxyReq.on("connect", (res, socket) => {
 73→      if (res.statusCode !== 200) {
 74→        reject(new Error(`Proxy CONNECT failed: ${res.statusCode}`));
 75→        return;
 76→      }
 77→
 78→      // Step 2: TLS handshake over the tunnel
 79→      const tlsSocket = tls.connect({
 80→        host: targetHost,
 81→        socket: socket,
 82→        servername: targetHost,
 83→      }, () => {
 84→        const payload = { text };
 85→        if (TTS_REFERENCE_ID) payload.reference_id = TTS_REFERENCE_ID;
 86→        const body = JSON.stringify(payload);
 87→        const reqStr = [
 88→          `POST /v1/tts HTTP/1.1`,
 89→          `Host: ${targetHost}`,
 90→          `Content-Type: application/json`,
 91→          `Authorization: Bearer ${TTS_API_KEY}`,
 92→          `model: ${TTS_MODEL}`,
 93→          `Content-Length: ${Buffer.byteLength(body)}`,
 94→          `Connection: close`,
 95→          ``,
 96→          body,
 97→        ].join("\r\n");
 98→
 99→        tlsSocket.write(reqStr);
100→      });
101→
102→      const chunks = [];
103→      let headerParsed = false;
104→      let headerBuf = Buffer.alloc(0);
105→      let statusCode = 0;
106→
107→      tlsSocket.on("data", (chunk) => {
108→        if (!headerParsed) {
109→          headerBuf = Buffer.concat([headerBuf, chunk]);
110→          const headerEnd = headerBuf.indexOf("\r\n\r\n");
111→          if (headerEnd !== -1) {
112→            const headerStr = headerBuf.slice(0, headerEnd).toString();
113→            const statusLine = headerStr.split("\r\n")[0];
114→            statusCode = parseInt(statusLine.split(" ")[1]);
115→            headerParsed = true;
116→            const bodyStart = headerBuf.slice(headerEnd + 4);
117→            if (bodyStart.length > 0) chunks.push(bodyStart);
118→          }
119→        } else {
120→          chunks.push(chunk);
121→        }
122→      });
123→
124→      tlsSocket.on("end", () => {
125→        const body = Buffer.concat(chunks);
126→        if (statusCode !== 200) {
127→          reject(new Error(`TTS API ${statusCode}: ${body.toString().slice(0, 200)}`));
128→        } else {
129→          resolve(body);
130→        }
131→      });
132→
133→      tlsSocket.on("error", reject);
134→    });
135→
136→    proxyReq.on("error", reject);
137→    proxyReq.on("timeout", () => { proxyReq.destroy(); reject(new Error("Proxy connect timeout")); });
138→    proxyReq.setTimeout(120000);
139→    proxyReq.end();
140→  });
141→}
142→
143→function applySpeed(inputPath, outputPath, tempo) {
144→  execSync(
145→    `ffmpeg -y -i "${inputPath}" -filter:a "atempo=${tempo}" -ar 44100 "${outputPath}" 2>/dev/null`
146→  );
147→}
148→
149→function getAudioDuration(filePath) {
150→  const out = execSync(
151→    `ffprobe -v quiet -show_entries format=duration -of csv=p=0 "${filePath}"`,
152→    { encoding: "utf-8" }
153→  );
154→  return parseFloat(out.trim());
155→}
156→
157→// =============================================================
158→// 并行控制
159→// =============================================================
160→
161→async function processChunk(chunk) {
162→  const mp3Path = path.join(outdir, `${chunk.id}.mp3`);
163→  const wavPath = path.join(outdir, `${chunk.id}.wav`);
164→
165→  console.log(`  [TTS] ${chunk.id}: "${chunk.text_normalized.slice(0, 40)}..."`);
166→
167→  // 重试 3 次
168→  let lastErr;
169→  for (let attempt = 1; attempt <= 3; attempt++) {
170→    try {
171→      const audioBuffer = await callTTS(chunk.text_normalized);
172→      fs.writeFileSync(mp3Path, audioBuffer);
173→      applySpeed(mp3Path, wavPath, speed);
174→      fs.unlinkSync(mp3Path);
175→
176→      const duration = getAudioDuration(wavPath);
177→      console.log(`    → ${chunk.id}.wav (${duration.toFixed(2)}s)`);
178→
179→      return { id: chunk.id, duration_s: Math.round(duration * 1000) / 1000, file: `${chunk.id}.wav`, status: "synth_done" };
180→    } catch (e) {
181→      lastErr = e;
182→      console.error(`    [RETRY ${attempt}/3] ${chunk.id}: ${e.message}`);
183→      if (attempt < 3) await new Promise((r) => setTimeout(r, 1000 * Math.pow(2, attempt - 1)));
184→    }
185→  }
186→
187→  console.error(`    [FAIL] ${chunk.id}: ${lastErr.message}`);
188→  return { id: chunk.id, duration_s: 0, file: null, status: "synth_failed", error: lastErr.message };
189→}
190→
191→async function runWithConcurrency(items, fn, limit) {
192→  const results = [];
193→  let idx = 0;
194→
195→  async function worker() {
196→    while (idx < items.length) {
197→      const i = idx++;
198→      results[i] = await fn(items[i]);
199→    }
200→  }
201→
202→  const workers = Array.from({ length: Math.min(limit, items.length) }, () => worker());
203→  await Promise.all(workers);
204→  return results;
205→}
206→
207→// =============================================================
208→// Main
209→// =============================================================
210→
211→async function main() {
212→  const chunks = JSON.parse(fs.readFileSync(chunksPath, "utf-8"));
213→  fs.mkdirSync(outdir, { recursive: true });
214→
215→  // 过滤要处理的 chunks
216→  let toProcess;
217→  if (targetChunk) {
218→    toProcess = chunks.filter((c) => c.id === targetChunk);
219→    if (toProcess.length === 0) {
220→      console.error(`Chunk "${targetChunk}" not found`);
221→      process.exit(1);
222→    }
223→  } else {
224→    toProcess = chunks.filter((c) => c.status === "pending" || c.status === "synth_failed");
225→  }
226→
227→  console.log(`=== P2: Synthesizing ${toProcess.length} chunk(s), concurrency=${CONCURRENCY}, speed=${speed}x ===\n`);
228→
229→  const results = await runWithConcurrency(toProcess, processChunk, CONCURRENCY);
230→
231→  // 更新 chunks.json 的 status
232→  for (const r of results) {
233→    const chunk = chunks.find((c) => c.id === r.id);
234→    if (chunk) {
235→      chunk.status = r.status;
236→      chunk.duration_s = r.duration_s;
237→      chunk.file = r.file;
238→      if (r.error) chunk.error = r.error;
239→    }
240→  }
241→
242→  fs.writeFileSync(chunksPath, JSON.stringify(chunks, null, 2));
243→
244→  // 摘要
245→  const ok = results.filter((r) => r.status === "synth_done").length;
246→  const fail = results.filter((r) => r.status === "synth_failed").length;
247→  const totalDur = results.reduce((s, r) => s + r.duration_s, 0);
248→
249→  console.log(`\n=== Done: ${ok} ok, ${fail} failed, total ${totalDur.toFixed(1)}s ===`);
250→  if (fail > 0) process.exit(1);
251→}
252→
253→main().catch((e) => {
254→  console.error(e);
255→  process.exit(1);
256→});
257→

  1→#!/usr/bin/env node
  2→/**
  3→ * P5 — 字幕生成
  4→ *
  5→ * 复用 P3 WhisperX 时间戳，将原始文稿文本与精确时间戳组合，
  6→ * 输出 per-shot subtitles.json，供 Remotion 消费。
  7→ *
  8→ * 关键：字幕文本用 text（原始文稿），时间戳用 WhisperX 转写对齐结果。
  9→ *
 10→ * Usage:
 11→ *   node scripts/p5-subtitles.js --chunks <chunks.json> --transcripts <dir> --outdir <dir>
 12→ */
 13→
 14→const fs = require("fs");
 15→const path = require("path");
 16→
 17→// --- 参数解析 ---
 18→const args = process.argv.slice(2);
 19→let chunksPath = "";
 20→let transcriptsDir = "";
 21→let outdir = "";
 22→
 23→for (let i = 0; i < args.length; i++) {
 24→  if (args[i] === "--chunks" && args[i + 1]) chunksPath = args[++i];
 25→  else if (args[i] === "--transcripts" && args[i + 1]) transcriptsDir = args[++i];
 26→  else if (args[i] === "--outdir" && args[i + 1]) outdir = args[++i];
 27→}
 28→
 29→if (!chunksPath || !transcriptsDir || !outdir) {
 30→  console.error(
 31→    "Usage: node p5-subtitles.js --chunks <chunks.json> --transcripts <dir> --outdir <dir>"
 32→  );
 33→  process.exit(1);
 34→}
 35→
 36→// =============================================================
 37→// 字幕分行（每行不超过 20 汉字）
 38→// =============================================================
 39→
 40→const MAX_LINE_CHARS = 20;
 41→
 42→/**
 43→ * 将一段原始文本按句号/逗号/顿号分行，每行不超过 MAX_LINE_CHARS
 44→ */
 45→function splitSubtitleLines(text) {
 46→  // 先按自然句界切分
 47→  const parts = text.split(/(?<=[。？！，、；,])/);
 48→  const lines = [];
 49→  let buffer = "";
 50→
 51→  for (const part of parts) {
 52→    if (buffer.length + part.length <= MAX_LINE_CHARS) {
 53→      buffer += part;
 54→    } else {
 55→      if (buffer) lines.push(buffer);
 56→      // 如果 part 本身超长，硬切
 57→      if (part.length > MAX_LINE_CHARS) {
 58→        for (let i = 0; i < part.length; i += MAX_LINE_CHARS) {
 59→          lines.push(part.slice(i, i + MAX_LINE_CHARS));
 60→        }
 61→        buffer = "";
 62→      } else {
 63→        buffer = part;
 64→      }
 65→    }
 66→  }
 67→  if (buffer) lines.push(buffer);
 68→
 69→  return lines;
 70→}
 71→
 72→// =============================================================
 73→// Main
 74→// =============================================================
 75→
 76→function main() {
 77→  const chunks = JSON.parse(fs.readFileSync(chunksPath, "utf-8"));
 78→  fs.mkdirSync(outdir, { recursive: true });
 79→
 80→  // 按 shot 分组
 81→  const shotMap = new Map();
 82→  for (const chunk of chunks) {
 83→    if (chunk.status !== "validated" && chunk.status !== "transcribed") continue;
 84→    const shotId = chunk.shot_id;
 85→    if (!shotMap.has(shotId)) shotMap.set(shotId, []);
 86→    shotMap.get(shotId).push(chunk);
 87→  }
 88→
 89→  const allShotSubtitles = {};
 90→  let totalSubs = 0;
 91→
 92→  for (const [shotId, shotChunks] of shotMap) {
 93→    const chunksSubs = [];
 94→
 95→    for (const chunk of shotChunks) {
 96→      const transcriptPath = path.join(transcriptsDir, `${chunk.id}.json`);
 97→      if (!fs.existsSync(transcriptPath)) {
 98→        console.error(`  [WARN] ${chunk.id}: transcript not found, skipping`);
 99→        continue;
100→      }
101→
102→      const transcript = JSON.parse(fs.readFileSync(transcriptPath, "utf-8"));
103→
104→      // 用 WhisperX 的 segment 时间戳，文本用原始文稿
105→      // 策略：WhisperX segments 提供时间边界，原始文稿按行分配到这些时间窗口
106→      const segments = transcript.segments || [];
107→      const originalLines = splitSubtitleLines(chunk.text);
108→
109→      if (segments.length === 0) {
110→        console.error(`  [WARN] ${chunk.id}: no segments in transcript`);
111→        continue;
112→      }
113→
114→      // 简单策略：用 segments 的首尾时间覆盖整个 chunk，
115→      // 然后按原文各行的字数比例分配时间
116→      const chunkStart = segments[0].start;
117→      const chunkEnd = segments[segments.length - 1].end;
118→      const chunkDuration = chunkEnd - chunkStart;
119→      const totalChars = originalLines.reduce((s, l) => s + l.length, 0);
120→
121→      // 生成 chunk 内相对时间戳（从 0 开始），P6 负责全局偏移
122→      const subtitles = [];
123→      let cursor = 0;
124→      for (const line of originalLines) {
125→        const lineDuration = (line.length / totalChars) * chunkDuration;
126→        subtitles.push({
127→          id: `sub_${String(totalSubs + subtitles.length + 1).padStart(3, "0")}`,
128→          text: line,
129→          start: round3(cursor),
130→          end: round3(cursor + lineDuration),
131→        });
132→        cursor += lineDuration;
133→      }
134→
135→      chunksSubs.push({
136→        chunk_id: chunk.id,
137→        subtitles,
138→      });
139→      totalSubs += subtitles.length;
140→    }
141→
142→    allShotSubtitles[shotId] = { chunks: chunksSubs };
143→    const shotSubCount = chunksSubs.reduce((s, c) => s + c.subtitles.length, 0);
144→    console.log(`  ${shotId}: ${shotSubCount} subtitle lines (${chunksSubs.length} chunks)`);
145→  }
146→
147→  // 输出
148→  const outPath = path.join(outdir, "subtitles.json");
149→  fs.writeFileSync(outPath, JSON.stringify(allShotSubtitles, null, 2));
150→  console.log(`\n=== Output: ${outPath} (${totalSubs} lines across ${shotMap.size} shots) ===`);
151→}
152→
153→function round3(n) {
154→  return Math.round(n * 1000) / 1000;
155→}
