  1→#!/usr/bin/env node
  2→/**
  3→ * P6 — 音频拼接 + Crossfade
  4→ *
  5→ * 将同一 shot 的多个 chunk 音频拼接为一个 WAV，
  6→ * 段落内 crossfade，段落间静音间隔。
  7→ * 同时更新 subtitles.json 的全局偏移。
  8→ *
  9→ * Usage:
 10→ *   node scripts/p6-concat.js --chunks <chunks.json> --audiodir <dir> --subtitles <subtitles.json> --outdir <dir>
 11→ */
 12→
 13→const fs = require("fs");
 14→const path = require("path");
 15→const { execSync } = require("child_process");
 16→
 17→// --- 配置 ---
 18→const CROSSFADE_MS = 50;          // 段落内 chunk 间 crossfade
 19→const PARAGRAPH_GAP_MS = 200;     // 段落间静音
 20→const PADDING_MS = 200;           // 首尾 padding
 21→
 22→// --- 参数解析 ---
 23→const args = process.argv.slice(2);
 24→let chunksPath = "";
 25→let audiodir = "";
 26→let subtitlesPath = "";
 27→let outdir = "";
 28→
 29→for (let i = 0; i < args.length; i++) {
 30→  if (args[i] === "--chunks" && args[i + 1]) chunksPath = args[++i];
 31→  else if (args[i] === "--audiodir" && args[i + 1]) audiodir = args[++i];
 32→  else if (args[i] === "--subtitles" && args[i + 1]) subtitlesPath = args[++i];
 33→  else if (args[i] === "--outdir" && args[i + 1]) outdir = args[++i];
 34→}
 35→
 36→if (!chunksPath || !audiodir || !subtitlesPath || !outdir) {
 37→  console.error(
 38→    "Usage: node p6-concat.js --chunks <chunks.json> --audiodir <dir> --subtitles <subtitles.json> --outdir <dir>"
 39→  );
 40→  process.exit(1);
 41→}
 42→
 43→// =============================================================
 44→// ffmpeg helpers
 45→// =============================================================
 46→
 47→function getAudioDuration(filePath) {
 48→  const out = execSync(
 49→    `ffprobe -v quiet -show_entries format=duration -of csv=p=0 "${filePath}"`,
 50→    { encoding: "utf-8" }
 51→  );
 52→  return parseFloat(out.trim());
 53→}
 54→
 55→/**
 56→ * 拼接多个 WAV → 单个 WAV，使用 ffmpeg concat filter
 57→ * 简单方案：先生成静音 padding，然后用 concat 协议拼接
 58→ */
 59→function concatWavFiles(wavPaths, outputPath) {
 60→  if (wavPaths.length === 0) return;
 61→
 62→  if (wavPaths.length === 1) {
 63→    // 单个 chunk：生成 padding WAV，用 concat demuxer 拼接
 64→    const paddingPath = path.resolve(outputPath + ".padding.wav");
 65→    const listPath = path.resolve(outputPath + ".list.txt");
 66→    const absOutput = path.resolve(outputPath);
 67→    execSync(
 68→      `ffmpeg -y -f lavfi -i anullsrc=r=44100:cl=mono -t ${PADDING_MS / 1000} "${paddingPath}" 2>/dev/null`
 69→    );
 70→    fs.writeFileSync(listPath, [
 71→      `file '${paddingPath}'`,
 72→      `file '${path.resolve(wavPaths[0])}'`,
 73→      `file '${paddingPath}'`,
 74→    ].join("\n"));
 75→    execSync(
 76→      `ffmpeg -y -f concat -safe 0 -i "${listPath}" -ar 44100 -ac 1 "${absOutput}" 2>/dev/null`
 77→    );
 78→    [listPath, paddingPath].forEach((f) => { try { fs.unlinkSync(f); } catch {} });
 79→    return;
 80→  }
 81→
 82→  // 多个 chunk：用 concat demuxer
 83→  const listPath = outputPath + ".list.txt";
 84→  const paddingPath = outputPath + ".padding.wav";
 85→  const gapPath = outputPath + ".gap.wav";
 86→
 87→  // 生成 padding 和 gap 静音
 88→  execSync(
 89→    `ffmpeg -y -f lavfi -i anullsrc=r=44100:cl=mono -t ${PADDING_MS / 1000} "${paddingPath}" 2>/dev/null`
 90→  );
 91→  execSync(
 92→    `ffmpeg -y -f lavfi -i anullsrc=r=44100:cl=mono -t ${CROSSFADE_MS / 1000} "${gapPath}" 2>/dev/null`
 93→  );
 94→
 95→  // 构建 concat 列表
 96→  const lines = [`file '${paddingPath}'`];
 97→  for (let i = 0; i < wavPaths.length; i++) {
 98→    lines.push(`file '${wavPaths[i]}'`);
 99→    if (i < wavPaths.length - 1) {
100→      lines.push(`file '${gapPath}'`);
101→    }
102→  }
103→  lines.push(`file '${paddingPath}'`);
104→
105→  fs.writeFileSync(listPath, lines.join("\n"));
106→  execSync(
107→    `ffmpeg -y -f concat -safe 0 -i "${listPath}" -ar 44100 -ac 1 "${outputPath}" 2>/dev/null`
108→  );
109→
110→  // 清理临时文件
111→  [listPath, paddingPath, gapPath].forEach((f) => {
112→    try { fs.unlinkSync(f); } catch {}
113→  });
114→}
115→
116→// =============================================================
117→// Main
118→// =============================================================
119→
120→function main() {
121→  const chunks = JSON.parse(fs.readFileSync(chunksPath, "utf-8"));
122→  const subtitles = JSON.parse(fs.readFileSync(subtitlesPath, "utf-8"));
123→  fs.mkdirSync(outdir, { recursive: true });
124→
125→  // 按 shot 分组
126→  const shotMap = new Map();
127→  for (const chunk of chunks) {
128→    if (!chunk.file) continue;
129→    const shotId = chunk.shot_id;
130→    if (!shotMap.has(shotId)) shotMap.set(shotId, []);
131→    shotMap.get(shotId).push(chunk);
132→  }
133→
134→  const durations = [];
135→
136→  for (const [shotId, shotChunks] of shotMap) {
137→    const wavPaths = shotChunks
138→      .map((c) => path.join(audiodir, c.file))
139→      .filter((p) => fs.existsSync(p));
140→
141→    if (wavPaths.length === 0) {
142→      console.log(`  [SKIP] ${shotId}: no audio files`);
143→      continue;
144→    }
145→
146→    const outputPath = path.join(outdir, `${shotId}.wav`);
147→    console.log(`  [CONCAT] ${shotId}: ${wavPaths.length} chunks → ${outputPath}`);
148→
149→    concatWavFiles(wavPaths, outputPath);
150→
151→    const duration = getAudioDuration(outputPath);
152→    console.log(`    → ${duration.toFixed(2)}s`);
153→
154→    durations.push({
155→      id: shotId,
156→      duration_s: Math.round(duration * 1000) / 1000,
157→      file: `${shotId}.wav`,
158→    });
159→
160→    // 根据 concat 结构计算每个 chunk 的实际时间偏移，应用到字幕
161→    // concat 结构: [padding] [chunk0] [gap] [chunk1] [gap] [chunk2] ... [padding]
162→    if (subtitles[shotId] && subtitles[shotId].chunks) {
163→      const flatSubs = [];
164→      let chunkOffset = PADDING_MS / 1000; // 第一个 chunk 从 padding 后开始
165→
166→      for (let ci = 0; ci < subtitles[shotId].chunks.length; ci++) {
167→        const chunkEntry = subtitles[shotId].chunks[ci];
168→
169→        // 找到对应的 chunk 音频时长
170→        const matchedChunk = shotChunks.find((c) => c.id === chunkEntry.chunk_id);
171→        const chunkDuration = matchedChunk ? (matchedChunk.duration_s || 0) : 0;
172→
173→        for (const sub of chunkEntry.subtitles) {
174→          flatSubs.push({
175→            id: sub.id,
176→            text: sub.text,
177→            start: Math.round((sub.start + chunkOffset) * 1000) / 1000,
178→            end: Math.round((sub.end + chunkOffset) * 1000) / 1000,
179→          });
180→        }
181→
182→        // 下一个 chunk 的偏移 = 当前偏移 + chunk 时长 + gap
183→        if (ci < subtitles[shotId].chunks.length - 1) {
184→          chunkOffset += chunkDuration + CROSSFADE_MS / 1000;
185→        }
186→      }
187→
188→      subtitles[shotId] = flatSubs;
189→    }
190→  }
191→
192→  // 写入 durations.json
193→  const durPath = path.join(outdir, "durations.json");
194→  fs.writeFileSync(durPath, JSON.stringify(durations, null, 2));
195→
196→  // 回写更新后的 subtitles
197→  fs.writeFileSync(subtitlesPath, JSON.stringify(subtitles, null, 2));
198→
199→  console.log(`\n=== Output ===`);
200→  console.log(`  Audio: ${outdir}/<shot>.wav`);
201→  console.log(`  Durations: ${durPath}`);
202→  console.log(`  Subtitles: ${subtitlesPath} (偏移已更新)`);
203→}
204→
205→main();
206→

  1→#!/usr/bin/env node
  2→/**
  3→ * Deterministic pre-checks between pipeline stages.
  4→ * Run cheap validation before expensive AI calls.
  5→ *
  6→ * Usage:
  7→ *   node scripts/precheck.js --stage p2 --chunks <chunks.json> --audiodir <dir>
  8→ *   node scripts/precheck.js --stage p3 --chunks <chunks.json> --transcripts <dir>
  9→ */
 10→
 11→const fs = require("fs");
 12→const path = require("path");
 13→const { execSync } = require("child_process");
 14→
 15→const args = process.argv.slice(2);
 16→let stage = "";
 17→let chunksPath = "";
 18→let audiodir = "";
 19→let transcriptsDir = "";
 20→
 21→for (let i = 0; i < args.length; i++) {
 22→  if (args[i] === "--stage" && args[i + 1]) stage = args[++i];
 23→  else if (args[i] === "--chunks" && args[i + 1]) chunksPath = args[++i];
 24→  else if (args[i] === "--audiodir" && args[i + 1]) audiodir = args[++i];
 25→  else if (args[i] === "--transcripts" && args[i + 1]) transcriptsDir = args[++i];
 26→}
 27→
 28→if (!stage || !chunksPath) {
 29→  console.error("Usage: node precheck.js --stage <p2|p3> --chunks <chunks.json> [--audiodir <dir>] [--transcripts <dir>]");
 30→  process.exit(1);
 31→}
 32→
 33→const chunks = JSON.parse(fs.readFileSync(chunksPath, "utf-8"));
 34→let errors = 0;
 35→
 36→function getAudioDuration(filePath) {
 37→  try {
 38→    const out = execSync(
 39→      `ffprobe -v quiet -show_entries format=duration -of csv=p=0 "${filePath}"`,
 40→      { encoding: "utf-8" }
 41→    );
 42→    return parseFloat(out.trim());
 43→  } catch {
 44→    return -1;
 45→  }
 46→}
 47→
 48→// ========== Post-P2 checks ==========
 49→if (stage === "p2") {
 50→  console.log("=== Pre-check: Post-P2 (TTS output validation) ===\n");
 51→
 52→  const synthDone = chunks.filter(c => c.status === "synth_done");
 53→  for (const chunk of synthDone) {
 54→    const wavPath = path.join(audiodir, `${chunk.id}.wav`);
 55→
 56→    // Check 1: file exists
 57→    if (!fs.existsSync(wavPath)) {
 58→      console.error(`  ✗ ${chunk.id}: WAV file missing at ${wavPath}`);
 59→      errors++;
 60→      continue;
 61→    }
 62→
 63→    // Check 2: duration > 0 and < 60s
 64→    const dur = getAudioDuration(wavPath);
 65→    if (dur <= 0) {
 66→      console.error(`  ✗ ${chunk.id}: WAV duration is ${dur}s (invalid)`);
 67→      errors++;
 68→    } else if (dur > 60) {
 69→      console.error(`  ✗ ${chunk.id}: WAV duration ${dur.toFixed(1)}s exceeds 60s limit`);
 70→      errors++;
 71→    } else {
 72→      // Check 3: duration is reasonable for text length (rough: 3-8 chars/sec for Chinese)
 73→      const charsPerSec = chunk.char_count / dur;
 74→      if (charsPerSec < 2 || charsPerSec > 12) {
 75→        console.warn(`  ⚠ ${chunk.id}: ${chunk.char_count} chars in ${dur.toFixed(1)}s = ${charsPerSec.toFixed(1)} chars/s (unusual)`);
 76→      } else {
 77→        console.log(`  ✓ ${chunk.id}: ${dur.toFixed(1)}s, ${charsPerSec.toFixed(1)} chars/s`);
 78→      }
 79→    }
 80→  }
 81→}
 82→
 83→// ========== Post-P3 checks ==========
 84→if (stage === "p3") {
 85→  console.log("=== Pre-check: Post-P3 (Transcription validation) ===\n");
 86→
 87→  const transcribed = chunks.filter(c => c.status === "transcribed");
 88→  for (const chunk of transcribed) {
 89→    const jsonPath = path.join(transcriptsDir, `${chunk.id}.json`);
 90→
 91→    // Check 1: file exists
 92→    if (!fs.existsSync(jsonPath)) {
 93→      console.error(`  ✗ ${chunk.id}: transcript JSON missing`);
 94→      errors++;
 95→      continue;
 96→    }
 97→
 98→    let transcript;
 99→    try {
100→      transcript = JSON.parse(fs.readFileSync(jsonPath, "utf-8"));
101→    } catch (e) {
102→      console.error(`  ✗ ${chunk.id}: invalid JSON — ${e.message}`);
103→      errors++;
104→      continue;
105→    }
106→
107→    // Check 2: has segments
108→    if (!transcript.segments || transcript.segments.length === 0) {
109→      console.error(`  ✗ ${chunk.id}: no segments in transcript`);
110→      errors++;
111→      continue;
112→    }
113→
114→    // Check 3: timestamps are monotonically increasing
115→    let lastEnd = -1;
116→    let monotonic = true;
117→    for (const seg of transcript.segments) {
118→      if (seg.start < lastEnd - 0.01) { // 10ms tolerance
119→        monotonic = false;
120→        break;
121→      }
122→      if (seg.end < seg.start) {
123→        monotonic = false;
124→        break;
125→      }
126→      lastEnd = seg.end;
127→    }
128→    if (!monotonic) {
129→      console.error(`  ✗ ${chunk.id}: timestamps not monotonically increasing`);
130→      errors++;
131→      continue;
132→    }
133→
134→    // Check 4: transcribed text length vs original (within 15% tolerance)
135→    const transcribedText = transcript.full_transcribed_text || "";
136→    const originalLen = chunk.text.replace(/[^\u4e00-\u9fff\w]/g, "").length; // count meaningful chars
137→    const transcribedLen = transcribedText.replace(/[^\u4e00-\u9fff\w]/g, "").length;
138→    const ratio = originalLen > 0 ? transcribedLen / originalLen : 0;
139→
140→    if (ratio < 0.7 || ratio > 1.3) {
141→      console.error(`  ✗ ${chunk.id}: char count mismatch — original ${originalLen}, transcribed ${transcribedLen} (ratio ${ratio.toFixed(2)})`);
142→      errors++;
143→    } else {
144→      console.log(`  ✓ ${chunk.id}: ${transcript.segments.length} segments, char ratio ${ratio.toFixed(2)}`);
145→    }
146→  }
147→}
148→
149→if (errors > 0) {
150→  console.error(`\n✗ ${errors} error(s) found. Fix before proceeding.`);
151→  process.exit(1);
152→} else {
153→  console.log(`\n✓ All checks passed.`);
154→}
155→

 1→// Usage in other scripts:
 2→// const { trace } = require("./trace");
 3→// trace(tracePath, { chunk: "shot02_chunk01", phase: "p2", event: "start" });
 4→// trace(tracePath, { chunk: "shot02_chunk01", phase: "p2", event: "done", duration_ms: 13200 });
 5→
 6→const fs = require("fs");
 7→
 8→function trace(tracePath, data) {
 9→  const entry = { ts: new Date().toISOString(), ...data };
10→  fs.appendFileSync(tracePath, JSON.stringify(entry) + "\n");
11→}
12→
13→function summary(tracePath) {
14→  if (!fs.existsSync(tracePath)) return;
15→  const lines = fs.readFileSync(tracePath, "utf-8").trim().split("\n").map(JSON.parse);
16→
17→  // Per-phase stats
18→  const phases = {};
19→  for (const l of lines) {
20→    if (l.event !== "done") continue;
21→    if (!phases[l.phase]) phases[l.phase] = { count: 0, total_ms: 0, errors: 0 };
22→    phases[l.phase].count++;
23→    phases[l.phase].total_ms += l.duration_ms || 0;
24→    if (l.error) phases[l.phase].errors++;
25→  }
26→
27→  console.log("\n=== Pipeline Trace Summary ===");
28→  for (const [phase, stats] of Object.entries(phases)) {
29→    const avg = stats.count ? Math.round(stats.total_ms / stats.count) : 0;
30→    console.log(`  ${phase}: ${stats.count} done, avg ${avg}ms, ${stats.errors} errors`);
31→  }
32→
33→  // P4 retry stats
34→  const p4Rounds = lines.filter(l => l.phase === "p4" && l.event === "done");
35→  if (p4Rounds.length > 0) {
36→    const rounds = p4Rounds.map(l => l.round || 1);
37→    const avgRound = (rounds.reduce((a, b) => a + b, 0) / rounds.length).toFixed(1);
38→    console.log(`  p4 avg rounds: ${avgRound}`);
39→  }
40→}
41→
42→module.exports = { trace, summary };
