  1→#!/usr/bin/env node
  2→/**
  3→ * V2 验收 — 生成 HTML 预览页
  4→ *
  5→ * 模拟 Remotion 的渐进字幕渲染：
  6→ * - 当前行逐字显示，已显示的字白色，未显示的暗灰
  7→ * - 语音播放位置用光标标记
  8→ * - 语音比字幕快时视觉上一目了然
  9→ *
 10→ * Usage:
 11→ *   node scripts/v2-preview.js --audiodir <dir> --subtitles <subtitles.json> --output <preview.html>
 12→ */
 13→
 14→const fs = require("fs");
 15→const path = require("path");
 16→
 17→const args = process.argv.slice(2);
 18→let audiodir = "";
 19→let subtitlesPath = "";
 20→let outputPath = "";
 21→
 22→for (let i = 0; i < args.length; i++) {
 23→  if (args[i] === "--audiodir" && args[i + 1]) audiodir = args[++i];
 24→  else if (args[i] === "--subtitles" && args[i + 1]) subtitlesPath = args[++i];
 25→  else if (args[i] === "--output" && args[i + 1]) outputPath = args[++i];
