131→  .timeline .sub-row.active .t { color: #a855f7; }
132→  .timeline .sub-row .txt { flex: 1; }
133→
134→  /* 进度条 */
135→  .progress-bar {
136→    width: 100%;
137→    height: 3px;
138→    background: #1a1a1a;
