151→<body>
152→<h1>TTS 字幕验收预览</h1>
153→<p class="hint">点击字幕行跳转 | 紫色光标 = 语音位置 | 白字 = 已读出 | 暗字 = 未读出 | 语音快于字幕时光标会跑到暗字区</p>
154→
155→${shots
156→  .map(
157→    (shot, idx) => `
158→<div class="shot" id="shot-${idx}">
159→  <div class="shot-header">
160→    <h2>${shot.id}</h2>
161→    <span class="badge">${shot.subtitles.length} lines</span>
162→  </div>
163→  <audio controls src="${shot.audioSrc}" data-shot-idx="${idx}"></audio>
164→  <div class="progress-bar"><div class="fill" id="prog-${idx}"></div></div>
165→  <div class="subtitle-stage" id="stage-${idx}">
166→    <div class="no-sub">--</div>
167→  </div>
168→  <div class="timeline" id="tl-${idx}">
169→    ${shot.subtitles
170→      .map(
171→        (s, si) =>
172→          '<div class="sub-row future" data-start="' + s.start + '" data-end="' + s.end + '" data-idx="' + si + '" data-shot="' + idx + '">' +
173→          '<span class="t">' + s.start.toFixed(2) + 's - ' + s.end.toFixed(2) + 's</span>' +
174→          '<span class="txt">' + s.text + '</span>' +
175→          '</div>'
176→      )
177→      .join("\n    ")}
178→  </div>
179→</div>`
180→  )
181→  .join("\n")}
182→
183→<script>
184→const shotsData = ${JSON.stringify(shots.map(s => s.subtitles))};
185→
186→document.querySelectorAll('audio').forEach(audio => {
187→  const idx = parseInt(audio.dataset.shotIdx);
188→  const subs = shotsData[idx];
189→  const stage = document.getElementById('stage-' + idx);
190→  const rows = document.querySelectorAll('#tl-' + idx + ' .sub-row');
191→  const progFill = document.getElementById('prog-' + idx);
192→
193→  audio.addEventListener('timeupdate', () => {
194→    const t = audio.currentTime;
195→    const duration = audio.duration || 1;
196→    progFill.style.width = ((t / duration) * 100) + '%';
197→
198→    // Find active subtitle
199→    let activeIdx = -1;
200→    for (let i = 0; i < subs.length; i++) {
201→      if (t >= subs[i].start && t < subs[i].end) { activeIdx = i; break; }
202→    }
203→
204→    // Update timeline rows
205→    rows.forEach((row, ri) => {
206→      row.className = 'sub-row ' + (ri < activeIdx ? 'past' : ri === activeIdx ? 'active' : 'future');
207→    });
208→
209→    // Update stage with progressive text
210→    if (activeIdx === -1) {
211→      stage.innerHTML = '<div class="no-sub">--</div>';
212→    } else {
213→      const sub = subs[activeIdx];
214→      const text = sub.text;
215→      const progress = (t - sub.start) / (sub.end - sub.start);
216→      const revealCount = Math.floor(progress * text.length);
217→
218→      const revealed = text.slice(0, revealCount);
219→      const unrevealed = text.slice(revealCount);
220→
221→      stage.innerHTML =
222→        '<div class="time-badge">' + t.toFixed(2) + 's / ' + sub.start.toFixed(2) + '-' + sub.end.toFixed(2) + '</div>' +
223→        '<div class="current-text">' +
224→          '<span class="revealed">' + escHtml(revealed) + '</span>' +
225→          '<span class="cursor"></span>' +
226→          '<span class="unrevealed">' + escHtml(unrevealed) + '</span>' +
227→        '</div>';
228→    }
229→  });
230→
231→  // Click row to seek
232→  rows.forEach(row => {
233→    row.addEventListener('click', () => {
234→      audio.currentTime = parseFloat(row.dataset.start);
235→      audio.play();
236→    });
237→  });
238→});
239→
240→function escHtml(s) {
241→  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
242→}
243→</script>
244→</body>
245→</html>`;
246→
247→fs.writeFileSync(outputPath, html);
248→console.log(`=== Preview: ${outputPath} ===`);
249→console.log(`  ${shots.length} shots, open in browser to review`);
