  1→#!/usr/bin/env node
  2→/**
  3→ * P4 — Claude 语义校验 + 自动修复循环
  4→ *
  5→ * 将原始文稿与 WhisperX 转写结果送入 Claude，执行语义级比对。
  6→ * FAIL 的 chunk 自动修改 text_normalized 并重跑 P2→P3→P4，最多 3 轮。
  7→ *
  8→ * 通过 CLIProxyAPI (localhost:8317) 调用 Claude API。
  9→ *
 10→ * Usage:
 11→ *   node scripts/p4-validate.js --chunks <chunks.json> --transcripts <dir> --audiodir <dir> --outdir <dir>
 12→ *   node scripts/p4-validate.js --chunks <chunks.json> --transcripts <dir> --audiodir <dir> --outdir <dir> --chunk shot02_chunk01
 13→ */
 14→
 15→const fs = require("fs");
 16→const path = require("path");
 17→const http = require("http");
 18→const { execSync } = require("child_process");
 19→
 20→// --- 配置 ---
 21→const CLAUDE_PROXY_URL = "http://localhost:8317/v1/messages";
 22→const CLAUDE_MODEL = "claude-sonnet-4-20250514";
 23→const MAX_RETRY_ROUNDS = 3;
 24→
 25→// --- 参数解析 ---
 26→const args = process.argv.slice(2);
 27→let chunksPath = "";
 28→let transcriptsDir = "";
 29→let audiodir = "";
 30→let outdir = "";
 31→let targetChunk = "";
 32→let venvPath = "";
 33→let p3ServerUrl = "";
 34→
 35→for (let i = 0; i < args.length; i++) {
 36→  if (args[i] === "--chunks" && args[i + 1]) chunksPath = args[++i];
 37→  else if (args[i] === "--transcripts" && args[i + 1]) transcriptsDir = args[++i];
 38→  else if (args[i] === "--audiodir" && args[i + 1]) audiodir = args[++i];
 39→  else if (args[i] === "--outdir" && args[i + 1]) outdir = args[++i];
 40→  else if (args[i] === "--chunk" && args[i + 1]) targetChunk = args[++i];
 41→  else if (args[i] === "--venv" && args[i + 1]) venvPath = args[++i];
 42→  else if (args[i] === "--p3-server" && args[i + 1]) p3ServerUrl = args[++i];
 43→}
 44→
 45→if (!chunksPath || !transcriptsDir || !audiodir || !outdir) {
 46→  console.error(
 47→    "Usage: node p4-validate.js --chunks <chunks.json> --transcripts <dir> --audiodir <dir> --outdir <dir> [--p3-server <url>]"
 48→  );
 49→  process.exit(1);
 50→}
 51→
 52→// 脚本路径（用于调用 P2/P3 重做）
 53→const SCRIPTS_DIR = path.dirname(__filename);
 54→
 55→// =============================================================
 56→// Claude API 调用
 57→// =============================================================
 58→
 59→function callClaude(prompt) {
 60→  return new Promise((resolve, reject) => {
 61→    const body = JSON.stringify({
 62→      model: CLAUDE_MODEL,
 63→      max_tokens: 2048,
 64→      messages: [{ role: "user", content: prompt }],
 65→    });
 66→
 67→    const url = new URL(CLAUDE_PROXY_URL);
 68→    const req = http.request(
 69→      {
 70→        hostname: url.hostname,
 71→        port: url.port,
 72→        path: url.pathname,
 73→        method: "POST",
 74→        headers: {
 75→          "Content-Type": "application/json",
 76→          "x-api-key": "placeholder",
 77→          "anthropic-version": "2023-06-01",
 78→          "Content-Length": Buffer.byteLength(body),
 79→        },
 80→        timeout: 60000,
 81→      },
 82→      (res) => {
 83→        const chunks = [];
 84→        res.on("data", (c) => chunks.push(c));
 85→        res.on("end", () => {
 86→          try {
 87→            const data = JSON.parse(Buffer.concat(chunks).toString());
 88→            if (data.error) {
 89→              reject(new Error(`Claude API error: ${JSON.stringify(data.error)}`));
 90→              return;
 91→            }
 92→            const text = data.content?.[0]?.text || "";
 93→            resolve(text);
 94→          } catch (e) {
 95→            reject(new Error(`Failed to parse Claude response: ${e.message}`));
 96→          }
 97→        });
 98→      }
 99→    );
100→    req.on("error", reject);
101→    req.on("timeout", () => { req.destroy(); reject(new Error("Claude API timeout")); });
102→    req.write(body);
103→    req.end();
104→  });
105→}
106→
107→// =============================================================
108→// Prompts
109→// =============================================================
110→
111→function buildValidatePrompt(original, normalized, transcribed) {
112→  return `你是一个中文 TTS 语音质量校验员。
113→
114→## 输入
115→
116→**原始脚本文本（用于字幕显示）**:
117→${original}
118→
119→**TTS 输入文本（经过符号替换的版本）**:
120→${normalized}
121→
122→**WhisperX 语音转文字结果（TTS 实际读出的内容）**:
123→${transcribed}
124→
125→## 任务
126→
127→比对「TTS 输入文本」和「转写结果」，识别 TTS 是否正确朗读了内容。
128→
129→检查以下问题：
130→1. **错读**：TTS 读错了字（如「-」读成「减」，英文名读错）
131→2. **漏读**：TTS 输入文本中有但语音中缺失的内容
132→3. **多读**：语音中出现但 TTS 输入文本没有的内容
133→4. **语义偏移**：虽然字面接近但含义改变
134→
135→**不算错误**：
136→- 同音字替换（的/地/得、做/作）
137→- 标点差异
138→- 轻微停顿差异
139→- 语气词增减（嗯、啊）
140→
141→## 输出格式
142→
143→严格输出 JSON，不要有任何其他内容：
144→{
145→  "passed": true/false,
146→  "issues": [
147→    {
148→      "type": "misread|missing|extra|semantic_drift",
149→      "location": "问题出现的位置描述",
150→      "original": "TTS 输入文本中的原文",
151→      "transcribed": "转写结果中的对应文本",
152→      "severity": "high|low",
153→      "fix": "建议如何修改 TTS 输入文本以避免此问题（仅 high severity 需要）"
154→    }
155→  ],
156→  "summary": "一句话总结校验结果"
157→}`;
158→}
159→
160→function buildFixPrompt(normalized, issues) {
161→  const issueList = issues
162→    .filter((i) => i.severity === "high")
163→    .map((i) => `- [${i.type}] "${i.original}" → "${i.transcribed}" | 建议: ${i.fix}`)
164→    .join("\n");
165→
166→  return `你是一个 TTS 文本优化专家。
167→
168→## 当前 TTS 输入文本
169→${normalized}
170→
171→## 发现的问题
172→${issueList}
173→
174→## 任务
175→
176→根据上述问题修改 TTS 输入文本，使 TTS 能正确朗读。修改原则：
177→- 只修改有问题的部分，不改其他内容
178→- 保持语义不变
179→- 用中文替代容易误读的符号和数字
180→- 英文缩写/品牌名如果被误读，加空格或用中文标注
181→
182→严格输出 JSON，不要有任何其他内容：
183→{
184→  "text_normalized": "修改后的完整 TTS 输入文本",
185→  "changes": ["修改1的说明", "修改2的说明"]
186→}`;
187→}
188→
189→// =============================================================
190→// 重做单个 chunk 的 P2→P3
191→// =============================================================
192→
193→function resynth(chunkId) {
194→  console.log(`      [RE-SYNTH] ${chunkId}...`);
195→  try {
196→    execSync(
197→      `node "${path.join(SCRIPTS_DIR, "p2-synth.js")}" --chunks "${chunksPath}" --outdir "${audiodir}" --chunk "${chunkId}"`,
198→      { stdio: "pipe", encoding: "utf-8" }
199→    );
200→  } catch (e) {
201→    throw new Error(`P2 re-synth failed: ${e.stderr || e.message}`);
202→  }
203→}
204→
205→function retranscribe(chunkId) {
206→  console.log(`      [RE-TRANSCRIBE] ${chunkId}...`);
207→
208→  // 读取 chunk 信息
209→  const chunks = JSON.parse(fs.readFileSync(chunksPath, "utf-8"));
210→  const chunk = chunks.find((c) => c.id === chunkId);
211→  if (!chunk) throw new Error(`Chunk ${chunkId} not found`);
212→
213→  if (p3ServerUrl) {
214→    // HTTP 模式 — 调用 P3 server，无需重新加载模型
215→    const body = JSON.stringify({
216→      audio_path: path.resolve(path.join(audiodir, `${chunkId}.wav`)),
217→      chunk_id: chunkId,
218→      shot_id: chunk.shot_id || "",
219→      text: chunk.text,
220→      text_normalized: chunk.text_normalized,
221→      outdir: path.resolve(transcriptsDir),
222→    });
223→
224→    const url = new URL(`${p3ServerUrl}/transcribe`);
225→    const res = execSync(
226→      `curl -s --noproxy 127.0.0.1 -X POST "http://${url.host}${url.pathname}" -H "Content-Type: application/json" -d '${body.replace(/'/g, "'\\''")}'`,
227→      { encoding: "utf-8", timeout: 120000 }
228→    );
229→
230→    const result = JSON.parse(res);
231→    if (result.error) throw new Error(`P3 server error: ${result.error}`);
232→
233→    // 更新 chunk status
234→    chunk.status = "transcribed";
235→    fs.writeFileSync(chunksPath, JSON.stringify(chunks, null, 2));
236→    console.log(`      转写: ${result.full_transcribed_text.slice(0, 50)}...`);
237→  } else {
238→    // Fallback — 启动 Python 进程（慢，但不需要 server）
239→    const pipelineDir = path.resolve(SCRIPTS_DIR, "..");
240→    const venv = venvPath || path.join(pipelineDir, ".venv", "bin", "python");
241→
242→    try {
243→      execSync(
244→        `"${venv}" "${path.join(SCRIPTS_DIR, "p3-transcribe.py")}" --chunks "${chunksPath}" --audiodir "${audiodir}" --outdir "${transcriptsDir}" --chunk "${chunkId}"`,
245→        { stdio: "pipe", encoding: "utf-8" }
246→      );
247→    } catch (e) {
248→      throw new Error(`P3 re-transcribe failed: ${e.stderr || e.message}`);
249→    }
250→  }
251→}
252→
253→// =============================================================
254→// 解析 LLM JSON 响应
255→// =============================================================
256→
257→function parseJSON(text) {
258→  try {
259→    return JSON.parse(text);
260→  } catch {
261→    // 尝试从 markdown code block 提取
262→    const match = text.match(/```(?:json)?\s*([\s\S]*?)```/);
263→    if (match) return JSON.parse(match[1]);
264→    // 尝试提取裸 JSON
265→    const match2 = text.match(/\{[\s\S]*\}/);
266→    if (match2) return JSON.parse(match2[0]);
267→    throw new Error("Cannot parse JSON from LLM response");
268→  }
269→}
270→
271→// =============================================================
272→// Main
273→// =============================================================
274→
275→async function main() {
276→  let chunks = JSON.parse(fs.readFileSync(chunksPath, "utf-8"));
277→  fs.mkdirSync(outdir, { recursive: true });
278→
279→  let toProcess;
280→  if (targetChunk) {
281→    toProcess = chunks.filter((c) => c.id === targetChunk);
282→  } else {
283→    toProcess = chunks.filter(
284→      (c) => c.status === "transcribed" || c.status === "validate_failed"
285→    );
286→  }
287→
288→  if (toProcess.length === 0) {
289→    console.log("No chunks to validate");
290→    return;
291→  }
292→
293→  console.log(`=== P4: Validating ${toProcess.length} chunk(s) with Claude ===\n`);
294→
295→  let passCount = 0;
296→  let failCount = 0;
297→  const needsHuman = [];
298→
299→  for (const chunkRef of toProcess) {
300→    // 重新读取最新状态（可能被重试循环更新）
301→    chunks = JSON.parse(fs.readFileSync(chunksPath, "utf-8"));
302→    const chunk = chunks.find((c) => c.id === chunkRef.id);
303→    if (!chunk) continue;
304→
305→    let passed = false;
306→
307→    for (let round = 1; round <= MAX_RETRY_ROUNDS; round++) {
308→      const transcriptPath = path.join(transcriptsDir, `${chunk.id}.json`);
309→      if (!fs.existsSync(transcriptPath)) {
310→        console.log(`  [SKIP] ${chunk.id}: transcript not found`);
311→        break;
312→      }
313→
314→      const transcript = JSON.parse(fs.readFileSync(transcriptPath, "utf-8"));
315→
316→      console.log(
317→        `  [VALIDATE] ${chunk.id} (round ${round}/${MAX_RETRY_ROUNDS})...`
318→      );
319→
320→      try {
321→        // Step 1: 校验
322→        const validateResponse = await callClaude(
323→          buildValidatePrompt(
324→            chunk.text,
325→            chunk.text_normalized,
326→            transcript.full_transcribed_text
327→          )
328→        );
329→        const result = parseJSON(validateResponse);
330→
331→        // 写入校验结果
332→        const outPath = path.join(outdir, `${chunk.id}_round${round}.json`);
333→        fs.writeFileSync(
334→          outPath,
335→          JSON.stringify(
336→            {
337→              chunk_id: chunk.id,
338→              round,
339→              original: chunk.text,
340→              normalized: chunk.text_normalized,
341→              transcribed: transcript.full_transcribed_text,
342→              ...result,
343→            },
344→            null,
345→            2
346→          )
347→        );
348→
349→        if (result.passed) {
350→          console.log(`    ✓ PASS — ${result.summary || "no issues"}`);
351→          chunk.status = "validated";
352→          chunk.validate_round = round;
353→          fs.writeFileSync(chunksPath, JSON.stringify(chunks, null, 2));
354→          passCount++;
355→          passed = true;
356→          break;
357→        }
358→
359→        // FAIL — 检查是否有 high severity
360→        const highIssues = (result.issues || []).filter(
361→          (i) => i.severity === "high"
362→        );
363→        const lowIssues = (result.issues || []).filter(
364→          (i) => i.severity === "low"
365→        );
366→
367→        console.log(
368→          `    ✗ FAIL — ${highIssues.length} high, ${lowIssues.length} low`
369→        );
370→        for (const issue of highIssues) {
371→          console.log(
372→            `      [${issue.type}] "${issue.original}" → "${issue.transcribed}"`
373→          );
374→        }
375→
376→        // 只有 low severity → 放行
377→        if (highIssues.length === 0) {
378→          console.log(`    → low severity only, auto-passing`);
379→          chunk.status = "validated";
380→          chunk.validate_round = round;
381→          chunk.low_issues = lowIssues;
382→          fs.writeFileSync(chunksPath, JSON.stringify(chunks, null, 2));
383→          passCount++;
384→          passed = true;
385→          break;
386→        }
387→
388→        // high severity + 还有重试机会 → 自动修复
389→        if (round < MAX_RETRY_ROUNDS) {
390→          console.log(`    → Auto-fixing text_normalized...`);
391→
392→          // Step 2: 让 Claude 修改 text_normalized
393→          const fixResponse = await callClaude(
394→            buildFixPrompt(chunk.text_normalized, highIssues)
395→          );
396→          const fix = parseJSON(fixResponse);
397→
398→          const oldNormalized = chunk.text_normalized;
399→          chunk.text_normalized = fix.text_normalized;
400→          chunk.status = "pending"; // 触发 P2 重做
401→
402→          console.log(`    → 修改: ${(fix.changes || []).join("; ")}`);
403→          console.log(
404→            `      旧: ${oldNormalized.slice(0, 60)}...`
405→          );
406→          console.log(
407→            `      新: ${chunk.text_normalized.slice(0, 60)}...`
408→          );
409→
410→          fs.writeFileSync(chunksPath, JSON.stringify(chunks, null, 2));
411→
412→          // Step 3: 重跑 P2 → P3
413→          resynth(chunk.id);
414→          retranscribe(chunk.id);
415→
416→          // 重新读取更新后的 chunks
417→          chunks = JSON.parse(fs.readFileSync(chunksPath, "utf-8"));
418→          const updatedChunk = chunks.find((c) => c.id === chunk.id);
419→          if (updatedChunk) Object.assign(chunk, updatedChunk);
420→        }
421→      } catch (e) {
422→        console.error(`    [ERROR] ${chunk.id}: ${e.message}`);
423→        break;
424→      }
425→    }
426→
427→    if (!passed) {
428→      chunk.status = "needs_human";
429→      fs.writeFileSync(chunksPath, JSON.stringify(chunks, null, 2));
430→      needsHuman.push(chunk);
431→      failCount++;
432→    }
433→  }
434→
435→  // 最终写入
436→  fs.writeFileSync(chunksPath, JSON.stringify(chunks, null, 2));
437→
438→  console.log(
439→    `\n=== Done: ${passCount} passed, ${failCount} needs human ===`
440→  );
441→
442→  if (needsHuman.length > 0) {
443→    console.log(`\n--- 需要人工介入的 chunk ---`);
444→    for (const c of needsHuman) {
445→      console.log(`  ${c.id}: 音频 → ${path.join(audiodir, c.file || "N/A")}`);
446→      const lastResult = fs
447→        .readdirSync(outdir)
448→        .filter((f) => f.startsWith(c.id) && f.endsWith(".json"))
449→        .sort()
450→        .pop();
451→      if (lastResult) {
